struct Point {
    x: f64,
    y: f64,
}

let x = 1.0;
let y = 2.0;
let p = Point { x, y };

impl Point {
    fn new(x: f64, y: f64) -> Self {
        Self { x, y }
    }
    fn distance(&self, other: &Point) -> f64 {
        ((self.x - other.x).powi(2)
            + (self.y - other.y).powi(2)).sqrt()
    }
}

